// WF99 Extract Error Context — Run Once for Each Item
const e = $json;
const exec = e.execution ?? {};
const wf = e.workflow ?? {};
const err = e.execution?.error ?? e.error ?? {};
return { json: {
  correlationId: err.correlationId ?? e.correlationId ?? null,
  workflowName: wf.name ?? null,
  executionId: exec.id ?? null,
  nodeName: err.node?.name ?? null,
  operation: e.operation ?? 'OTHER',
  statusCode: err.httpCode ?? err.statusCode ?? null,
  errorCode: err.code ?? null,
  message: (err.message ?? 'Unknown error').toString().slice(0, 500),
  attempt: e.attempt ?? null,
  payload: e.payload ?? {},
} };

// WF99 Classify + Sanitize — Run Once for Each Item
const status = $json.statusCode ?? 0;
const code = $json.errorCode ?? null;
function classify(status, code) {
  const map = { 400:['VALIDATION',false],401:['AUTHENTICATION',false],403:['AUTHORIZATION',false],404:['NOT_FOUND',false],408:['TIMEOUT',true],425:['DEPENDENCY_UNAVAILABLE',true],429:['RATE_LIMIT',true],500:['INTERNAL',true],502:['DEPENDENCY_UNAVAILABLE',true],503:['DEPENDENCY_UNAVAILABLE',true],504:['TIMEOUT',true] };
  if (status === 409) return code === 'IDEMPOTENCY_IN_PROGRESS' ? ['CONFLICT',true] : ['CONFLICT',false];
  return map[status] ?? ['UNKNOWN', false];
}
const SENSITIVE = ['authorization','x-api-key','apikey','api_key','password','secret','token','cookie','set-cookie'];
function sanitize(v, d = 0) {
  if (d > 5) return '[TRUNCATED]';
  if (Array.isArray(v)) return v.slice(0,100).map(x => sanitize(x, d+1));
  if (v && typeof v === 'object') { const o = {}; for (const k of Object.keys(v)) o[k] = SENSITIVE.includes(k.toLowerCase()) ? '[REDACTED]' : sanitize(v[k], d+1); return o; }
  if (typeof v === 'string' && v.length > 2000) return v.slice(0,2000) + '…';
  return v;
}
const [errorType, retryable] = classify(status, code);
return { json: { ...$json, errorType, retryable, payload: sanitize($json.payload) } };

